def compact_case(row: dict, search_text: str = "") -> dict:
    out = {k: row.get(k) for k in KEEP}
    out["search_text"] = search_text

    def derived_status(*keys: str) -> str:
        statuses = [row.get(f"{key}_analysis_status") for key in keys]
        if all(status == "ready" for status in statuses):
            return "ready"
        if all(status in {"ready", "usable_with_caution"} for status in statuses):
            return "usable_with_caution"
        if any(status == "review_required" for status in statuses):
            return "review_required"
        return "unavailable"

    cost = row.get("project_cost_million_yen_normalized")
    sales = row.get("sales_baseline_oku_yen")
    try:
        out["investment_sales_ratio_pct"] = round(float(cost) / float(sales), 3) if float(sales) else None
    except (TypeError, ValueError, ZeroDivisionError):
        out["investment_sales_ratio_pct"] = None
    out["investment_sales_ratio_analysis_status"] = derived_status("project_cost", "sales_values")

    def numeric(key: str) -> float:
        value = row.get(key)
        if value in (None, ""):
            raise ValueError(key)
        return float(value)

    try:
        value_added_raw = (
            numeric("labor_target_value_man_yen_per_person") * numeric("employees_target_value")
            - numeric("labor_base_value_man_yen_per_person") * numeric("employees_base_value")
        ) / 10_000
    except (TypeError, ValueError):
        value_added_raw = None
    out["value_added_increase_proxy_raw_oku"] = (
        round(value_added_raw, 6) if value_added_raw is not None else None
    )
    out["value_added_increase_estimated_oku"] = (
        round(value_added_raw * VALUE_ADDED_LEVEL_ADJUSTMENT, 6)
        if value_added_raw is not None
        else None
    )
    out["value_added_increase_estimated_analysis_status"] = (
        derived_status("labor_values", "employees_values")
        if value_added_raw is not None else "unavailable"
    )
    try:
        subsidy_oku = numeric("subsidy_million_yen_normalized") / 100
        value_added_ratio = value_added_raw / subsidy_oku * 100 if subsidy_oku else None
    except (TypeError, ValueError):
        value_added_ratio = None
    out["value_added_subsidy_ratio_proxy_pct"] = (
        round(value_added_ratio, 6) if value_added_ratio is not None else None
    )
    out["value_added_subsidy_ratio_proxy_analysis_status"] = (
        derived_status("labor_values", "employees_values", "subsidy")
        if value_added_ratio is not None else "unavailable"
    )

    return out


